#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int t,n,m,a[1003],C[1003][1003];
int main(){
	for(int i=0;i<=1001;i++)
		for(int j=0;j<=1001;j++)
			if(j==0 || j==i)
				C[i][j]=1;
			else
				C[i][j]=(C[i-1][j]+C[i-1][j-1])%mod;
	cin>>t;
	while(t--){
		cin>>n>>m;
		n=0;
		for(int i=1;i<=m;i++){
			cin>>a[i];
			n+=a[i];
		}
		long long ans=1;
		for(int i=1,rest=n;i<=m;rest-=a[i],i++)
			ans*=C[rest][a[i]],ans%=mod;
		printf("%lld\n",ans);
	}
	return 0;
}
